function TechSupport() {
  const techServices = [
    {
      title: "Computer Repair",
      description:
        "Get community support for basic laptop and computer problems such as slow performance and setup issues.",
    },
    {
      title: "Website Support",
      description:
        "Receive help with creating, updating, or improving simple websites for school or personal projects.",
    },
    {
      title: "Phone Setup",
      description:
        "Find support for installing apps, changing phone settings, and using common mobile services.",
    },
    {
      title: "Coding Guidance",
      description:
        "Ask for help with beginner programming concepts, simple code errors, and web development basics.",
    },
  ];

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Tech Support</h1>

        <p>
          Tech Support connects users with community members who can help with
          devices, websites, mobile apps, and basic programming questions.
        </p>
      </div>

      <section className="cards">
        {techServices.map((service, index) => (
          <div className="card" key={index}>
            <h3>{service.title}</h3>
            <p>{service.description}</p>
          </div>
        ))}
      </section>
    </section>
  );
}

export default TechSupport;
